parameters.jsCode:
const content = $json.choices?.[0]?.message?.content;

if (!content) {
  throw new Error('OpenAI não retornou choices[0].message.content. Verifique a resposta do nó anterior.');
}

let parsed;

try {
  parsed = typeof content === 'string' ? JSON.parse(content) : content;
} catch (error) {
  throw new Error('Resposta da OpenAI não é JSON válido: ' + content);
}

const required = [
  'estrategia_texto',
  'produto',
  'publico_alvo',
  'bairro',
  'canal_destino',
  'objetivo'
];

const missing = required.filter((field) => !parsed[field]);

if (missing.length > 0) {
  throw new Error('JSON da OpenAI incompleto. Campos ausentes: ' + missing.join(', '));
}

return {
  json: {
    estrategia_texto: parsed.estrategia_texto,
    produto: parsed.produto,
    publico_alvo: parsed.publico_alvo,
    bairro: parsed.bairro,
    canal_destino: parsed.canal_destino,
    objetivo: parsed.objetivo,
    origem_ia: 'openai',
    status_processamento: 'ok',
    criado_em: new Date().toISOString()
  }
};
